function solve(n) {
    // Calculate the sum of digits
    let digitSum = 0;
    let digitProduct = 1;
    let temp = n;

    while (temp > 0) {
        let digit = temp % 10;
        digitSum += digit;
        digitProduct *= digit;
        temp = Math.floor(temp / 10);
    }

    // Calculate the sum of the sum and product
    let total = digitSum + digitProduct;

    // Check if n is divisible by the total
    return n % total === 0;
}

